mapper.select:
SELECT id, execution_id, step_order, step_type, step_name, status, log, started_at, completed_at
FROM pipeline_step
WHERE execution_id = #{executionId} AND step_order = #{stepOrder}

mapper.update:
UPDATE pipeline_step
SET status = #{newStatus},
    log = #{log},
    completed_at = #{completedAt}
WHERE id = #{id}
  AND status = #{expectedStatus}
